// AWS IoT Device Defender Security Profile Setup
const AWS = require('aws-sdk');
const iotDefender = new AWS.IoTDeviceDefender({ region: 'us-east-1' });

// Create Security Profile for MQTT Flood Detection
const securityProfileParams = {
  securityProfileName: 'mqtt-flood-prevention',
  securityProfileDescription: 'Detects and prevents MQTT message flooding attacks',
  behaviors: [
    {
      name: 'high-message-rate-outbound',
      metric: 'aws:num-messages-sent',
      criteria: {
        comparisonOperator: 'greater-than',
        value: { count: 500 },          // Max 500 messages per 5 minutes
        durationSeconds: 300,
        consecutiveDatapointsToAlarm: 2,
        consecutiveDatapointsToClear: 1
      }
    },
    {
      name: 'excessive-connection-attempts',
      metric: 'aws:num-connection-attempts',
      criteria: {
        comparisonOperator: 'greater-than',
        value: { count: 10 },
        durationSeconds: 300,
        consecutiveDatapointsToAlarm: 1
      }
    },
    {
      name: 'abnormal-disconnect-rate',
      metric: 'aws:num-disconnects',
      criteria: {
        comparisonOperator: 'greater-than',
        value: { count: 5 },
        durationSeconds: 300
      }
    },
    {
      name: 'message-size-anomaly',
      metric: 'aws:message-byte-size',
      criteria: {
        comparisonOperator: 'greater-than',
        value: { count: 131072 },       // 128KB max message
        consecutiveDatapointsToAlarm: 1
      },
      suppressAlerts: false
    }
  ],
  alertTargets: {
    SNS: {
      alertTargetArn: 'arn:aws:sns:us-east-1:123456789012:iot-security-alerts',
      roleArn: 'arn:aws:iam::123456789012:role/IoTDeviceDefenderRole'
    }
  },
  additionalMetricsToRetainV2: [
    { metric: 'aws:num-messages-sent', exportMetric: true },
    { metric: 'aws:num-authorization-failures', exportMetric: true }
  ]
};

await iotDefender.createSecurityProfile(securityProfileParams).promise();

// Attach Security Profile to All Devices
await iotDefender.attachSecurityProfile({
  securityProfileName: 'mqtt-flood-prevention',
  securityProfileTargetArn: 'arn:aws:iot:us-east-1:123456789012:all/things'
}).promise();

// Automated Mitigation Action - Quarantine Device
const mitigation = {
  actionName: 'quarantine-flooding-device',
  roleArn: 'arn:aws:iam::123456789012:role/IoTMitigationRole',
  actionParams: {
    updateDeviceCertificateParams: {
      action: 'DEACTIVATE'
    },
    publishFindingToSnsParams: {
      topicArn: 'arn:aws:sns:us-east-1:123456789012:iot-mitigation-alerts'
    }
  }
};

await iotDefender.createMitigationAction(mitigation).promise();

// CloudWatch Logs Insights Query for Analysis
const logQuery = `
fields @timestamp, eventType, clientId, protocol, principalId
| filter eventType = "Connect" or eventType = "Publish"
| stats count(*) as eventCount by clientId, bin(5m)
| filter eventCount > 500
| sort eventCount desc
`;

console.log('AWS IoT Device Defender deployed successfully');
console.log('Monitor violations: https://console.aws.amazon.com/iot/home#/dd/securityProfiles');
